def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 1:
            priorities[i] = np.inf
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        score = 0.0
        power_sum = 0.0
        for j in range(1, 21):
            if j % 2 == 0:
                power_sum += (ratio ** j) / (j**1.5)
            else:
                power_sum -= (ratio ** j) / (j**1.5)
        score += power_sum
        penalty = 0
        if cap < item * 2:
            penalty += (item / cap) * 2
        elif cap < item * 3:
            penalty += (item / cap)
        else:
            penalty += (item / cap) * 0.5
        prime_factors = 0
        x = int(cap)
        for p in [2, 3, 5, 7, 11]:
            while x % p == 0 and x > 1:
                prime_factors += 1
                x //= p
        penalty += prime_factors * 0.1
        if item > cap / 2:
            score *= 1.5
        else:
            score *= 1.2
        final_score = -score + penalty
        if final_score < 0:
            final_score = 0
        priorities[i] = final_score
    for i in range(n):
        if priorities[i] == 0 and bins[i] != 0:
            cumulative = 0
            for j in range(n):
                if bins[j] > bins[i]:
                    cumulative += abs(priorities[j] - priorities[i])
            if cumulative > 1:
                priorities[i] = cumulative / n
    return priorities
